const p=(t="")=>String(t).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#39;"),s=(t="",r=new Set)=>{let l=p(t??"");return l=l.replace(/\[\[(.+?)\|(.+?)\]\]/g,(e,a,n)=>r.has(a.toLowerCase())?a:`<span class="vocab-word" data-word="${a}">${a}</span><span class="translation">(${n})</span>`),l.split(/\n+/).map(e=>e.trim()).filter(Boolean).map(e=>`<p>${e}</p>`).join("")};export{s as f};
